const wf = $json.workflow || {};
const exec = $json.execution || {};
const err = $json.error || {};
const lastNode = (err.node && (err.node.name || err.node.id)) || '';
const lines = [];
lines.push(`HomerTrakker ERROR`);
lines.push(`Workflow: ${wf.name || ''}`);
lines.push(`Execution ID: ${exec.id || ''}`);
lines.push(`Last Node: ${lastNode}`);
lines.push(`Message: ${err.message || ''}`);
lines.push(`Time: ${new Date().toISOString()}`);
const msg = lines.join('
');
return [{ json: { text: msg } }];
